# Generated by Codex for Pyomo DoE PDE diffusion diagnostic execution
"""
Run only the symbolic diagnostics into an existing analysis_execution folder.
"""

from __future__ import annotations

import argparse
import subprocess
from pathlib import Path
from typing import List, Tuple


DISCRETIZATIONS: List[Tuple[int, int]] = [
    (2, 2),
    (5, 10),
    (10, 20),
    (25, 40),
    (50, 75),
]


def parse_args() -> argparse.Namespace:
    """
    Parse CLI arguments.

    Returns:
        Parsed arguments namespace.
    """
    parser = argparse.ArgumentParser()
    parser.add_argument("--run_dir", type=str, required=True)
    return parser.parse_args()


def run_command(cmd: List[str]) -> None:
    """
    Run a subprocess command and raise on failure.

    Parameters:
        cmd: Command list to execute.
    """
    subprocess.run(cmd, check=True)


def confirm_environment(env_name: str) -> None:
    """
    Print sys.executable and pyomo.__version__ for the given conda environment.

    Parameters:
        env_name: Conda environment name.
    """
    cmd = [
        "conda",
        "run",
        "-n",
        env_name,
        "python",
        "-c",
        "import sys, pyomo; "
        "print('sys.executable=' + sys.executable); "
        "print('pyomo.__version__=' + str(pyomo.__version__))",
    ]
    run_command(cmd)


def run_helper(
    env_name: str,
    mode: str,
    nfe_x: int,
    nfe_t: int,
    out_json: Path,
    run_dir: Path,
    ipopt_out: Path,
) -> None:
    """
    Invoke the helper script inside the pyomosym environment.

    Parameters:
        env_name: Conda environment name.
        mode: "baseline", "no_solve", or "solve_twice".
        nfe_x: Spatial discretization.
        nfe_t: Temporal discretization.
        out_json: Output JSON path.
        run_dir: Run directory for IPOPT output.
        ipopt_out: IPOPT output file path.
    """
    cmd = [
        "conda",
        "run",
        "-n",
        env_name,
        "python",
        str(Path(__file__).parent / "pde_doe_execution_helper.py"),
        "--method",
        "symbolic",
        "--mode",
        mode,
        "--nfe_x",
        str(nfe_x),
        "--nfe_t",
        str(nfe_t),
        "--out_json",
        str(out_json),
        "--run_dir",
        str(run_dir),
        "--ipopt_out",
        str(ipopt_out),
    ]
    run_command(cmd)


def main() -> None:
    """
    Entry point for running symbolic-only diagnostics.
    """
    args = parse_args()
    run_dir = Path(args.run_dir)
    symbolic_dir = run_dir / "symbolic"
    baseline_dir = symbolic_dir / "baseline"
    no_solve_dir = symbolic_dir / "no_solve"
    solve_twice_dir = symbolic_dir / "solve_twice"

    baseline_dir.mkdir(parents=True, exist_ok=True)
    no_solve_dir.mkdir(parents=True, exist_ok=True)
    solve_twice_dir.mkdir(parents=True, exist_ok=True)

    confirm_environment("pyomosym")

    for nfe_x, nfe_t in DISCRETIZATIONS:
        for run_idx in range(1, 4):
            out_json = baseline_dir / f"baseline_nfe_x{nfe_x}_nfe_t{nfe_t}_run{run_idx}.json"
            ipopt_out = baseline_dir / f"ipopt_nfe_x{nfe_x}_nfe_t{nfe_t}_run{run_idx}.out"
            run_helper("pyomosym", "baseline", nfe_x, nfe_t, out_json, baseline_dir, ipopt_out)

    nfe_x, nfe_t = DISCRETIZATIONS[-1]
    out_json = no_solve_dir / f"no_solve_nfe_x{nfe_x}_nfe_t{nfe_t}.json"
    ipopt_out = no_solve_dir / f"ipopt_no_solve_nfe_x{nfe_x}_nfe_t{nfe_t}.out"
    run_helper("pyomosym", "no_solve", nfe_x, nfe_t, out_json, no_solve_dir, ipopt_out)

    out_json = solve_twice_dir / f"solve_twice_nfe_x{nfe_x}_nfe_t{nfe_t}.json"
    ipopt_out = solve_twice_dir / f"ipopt_solve1_nfe_x{nfe_x}_nfe_t{nfe_t}.out"
    run_helper("pyomosym", "solve_twice", nfe_x, nfe_t, out_json, solve_twice_dir, ipopt_out)

    print(f"Symbolic runs completed in: {symbolic_dir}")


if __name__ == "__main__":
    main()
